// ─── Build Transcription Payload ───
const body = $('Webhook Trigger').first().json.body;
const documents = body.documents || [];

const parts = [];

// Add each document
for (const doc of documents) {
  if (doc.type === 'inline') {
    parts.push({
      inline_data: {
        mime_type: doc.mime_type,
        data: doc.base64
      }
    });
  } else if (doc.type === 'text') {
    parts.push({ text: `[Content from ${doc.name}]:\n${doc.content}` });
  }
}

// Add the transcription prompt
parts.push({
  text: `You are a professional transcription assistant. You have been given ${documents.length} document(s) containing handwritten notes, essays, or mind maps.

Your task:
1. CAREFULLY read the handwriting in each document, in the exact order they were provided.
2. UNDERSTAND the logical flow and context across all pages — they form a single continuous document.
3. TRANSCRIBE the handwriting into clean, well-structured digital text.
4. PRESERVE the author's original intent, ideas, paragraph structure, and any headings or bullet points.
5. If the handwriting contains a mind map, convert it into a logical outline or structured text.
6. Separate content from different pages with a blank line, but maintain narrative continuity.
7. Fix obvious spelling errors in the handwriting, but do NOT add, remove, or rephrase the author's ideas.
8. DO identify if the author had struck through lines or massive crossing out — this means the user has removed that content and does not want it transcribed.
9. Do NOT add any commentary, preamble, or summary — output ONLY the transcribed text.

Begin transcription now:`
});

const geminiPayload = {
  contents: [{ parts }],
  generationConfig: {
    temperature: 0.2,
    topP: 0.8,
    topK: 40,
    maxOutputTokens: 8192
  },
  safetySettings: [
    { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
    { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
  ]
};

return { json: { geminiPayload } };

const response = $input.first().json;
let text = '';

try {
  if (response.body && response.body.candidates && response.body.candidates.length > 0) {
    const candidate = response.body.candidates[0];
    if (candidate.content && candidate.content.parts) {
      text = candidate.content.parts.filter(p => p.text).map(p => p.text).join('\n');
    }
  }
  if (!text && response.candidates && response.candidates.length > 0) {
    text = response.candidates[0].content.parts.filter(p => p.text).map(p => p.text).join('\n');
  }
  if (!text) throw new Error('No text extracted from Gemini response');
} catch (err) {
  throw new Error(`Gemini extraction failed: ${err.message}. Raw keys: ${JSON.stringify(Object.keys(response))}`);
}

return { json: { text: text.trim() } };

// ─── Build Template Generator Payload ───
const body = $('Webhook Trigger').first().json.body;
const documents = body.documents || [];
const userNotes = body.userNotes || '';

// Try to get scraped URL content
let scrapedContent = '';
try {
  const raw = $('Scrape Template URL').first().json;
  if (typeof raw === 'string') scrapedContent = raw;
  else if (raw.data) scrapedContent = String(raw.data);
  else if (raw.body) scrapedContent = String(raw.body);
} catch(e) { /* No scraped content */ }

// Strip HTML tags from scraped content
if (scrapedContent) {
  scrapedContent = scrapedContent.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();
  if (scrapedContent.length > 50000) scrapedContent = scrapedContent.substring(0, 50000) + '\n[Content truncated]';
}

const ROLE_LABELS = {
  instructions: 'ASSIGNMENT INSTRUCTIONS',
  rubric: 'GRADING RUBRIC',
  sources: 'SOURCE MATERIALS'
};

const parts = [];

// Add inline documents (images, PDFs)
for (const doc of documents) {
  parts.push({ text: `[${ROLE_LABELS[doc.role] || doc.role.toUpperCase()}: ${doc.name}]` });
  if (doc.type === 'inline') {
    parts.push({ inline_data: { mime_type: doc.mime_type, data: doc.base64 } });
  } else if (doc.type === 'text') {
    parts.push({ text: doc.content });
  }
}

// Add scraped URL content
if (scrapedContent) {
  parts.push({ text: `[ONLINE RESOURCE from ${body.url}]:\n${scrapedContent}` });
}

// Add student notes
if (userNotes) {
  parts.push({ text: `[STUDENT'S QUESTIONS/NOTES]:\n${userNotes}` });
}

// Add the template generator prompt
parts.push({
  text: `You are an expert university lecturer and academic guide. The user has provided documents that may include an assignment brief, a grading rubric, and source materials (study guides/articles).

Your task:
1. DECONSTRUCT the assignment into a clear, logical essay outline or structured template.
2. ALLOCATE a target word count for each section based on the overall limit.
3. PROVIDE specific clues and references for each section. Explicitly mention which provided source document (and what concepts) the student should use for that specific paragraph.
4. DO NOT write the essay for them. Act as a scaffolding tool to help them understand exactly what is required.
5. Format your response in clean Markdown with clear headings and bullet points.`
});

